          <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="8px">
            <Row justify="center" gap={32}>
            <Tooltip content="Current humidity percentage">
              <Text variant="label">Humidity: {props.humidity}%</Text>
            </Tooltip>
            <Tooltip content="Current wind speed">
              <Text variant="label">Wind: {props.windSpeed} km/h</Text>
            </Tooltip>
            </Row>
          </Box>
          <Divider margin="var(--ggui-spacing-2, 8px)" />
          <Row justify="between" style={{ overflowX: 'auto', padding: 'var(--ggui-spacing-2, 8px) 0' }}>
