import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: { id: string; title: string; priority: string; assignee: string; column: string; dueDate: string }[]; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTask, setNewTask] = useState({ title: '', priority: 'medium' });

  const columns = useMemo(() => props.columns.map(col => ({
    id: col.id || '',
    name: col.name || '',
    tasks: tasks.filter(t => t.column === col.id)
  })), [tasks, props.columns]);

  const handleMove = useCallback((taskId: string, newColumn: string) => {
    const updated = tasks.map(t => t.id === taskId ? { ...t, column: newColumn } : t);
    setTasks(updated);
    handleTaskUpdate({ taskId, action: 'move', newColumn });
  }, [tasks, handleTaskUpdate]);

  const handleAdd = useCallback((columnId: string) => {
    if (!newTask.title) return;
    const task = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTask.title,
      priority: newTask.priority,
      assignee: '??',
      column: columnId,
      dueDate: new Date().toISOString().split('T')[0]
    };
    setTasks([...tasks, task]);
    setNewTask({ title: '', priority: 'medium' });
    setAddingTo(null);
    handleTaskUpdate({ task, action: 'create' });
  }, [tasks, newTask, handleTaskUpdate]);

  return { columns, addingTo, setAddingTo, newTask, setNewTask, handleMove, handleAdd };
}

export default function Component(props: Props) {
  const { columns, addingTo, setAddingTo, newTask, setNewTask, handleMove, handleAdd } = useComponent(props);
  const total = props.tasks.length;
  const completed = props.tasks.filter(t => t.column === 'done').length;

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={16}>
        <Heading level={1}>Task Board</Heading>
        <Row justify="between">
          <Text>Total Tasks: {total} | Completed: {completed}</Text>
        </Row>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 'var(--ggui-spacing-4, 16px)' }}>
          {columns.map(col => (
            <Card key={col.id} padding={16}>
              <Stack gap={12}>
                <Heading level={4}>{col.name} ({col.tasks.length})</Heading>
                {col.tasks.map(task => (
                  <Card key={task.id} shadow="sm" padding={12} border={true} aria-label={`Task: ${task.title}`}>
                    <Stack gap={8}>
                      <Text variant="body">{task.title}</Text>
                      <Row justify="between">
                        <Badge variant={task.priority === 'high' ? 'error' : 'default'}>{task.priority}</Badge>
                        <Dropdown trigger={<Button size="xs" variant="ghost" aria-label="Move task to another column">Move</Button>} options={columns.filter(c => c.id !== col.id).map(c => ({ value: c.id, label: c.name }))} onChange={(colId) => handleMove(task.id, colId)} />
                      </Row>
                    </Stack>
                  </Card>
                ))}
                {addingTo === col.id ? (
                  <Stack gap={8}><Input label="Task title" placeholder="Enter task title" value={newTask.title} onChange={(val) => setNewTask({...newTask, title: val})} /><Select label="Priority" value={newTask.priority} onChange={(val) => setNewTask({...newTask, priority: val})} options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]} /><Button onClick={() => handleAdd(col.id)}>Add Task</Button></Stack>
                ) : (
                  <Button variant="ghost" onClick={() => setAddingTo(col.id)}>+ Add Task</Button>
                )}
              </Stack>
            </Card>
          ))}
        </div>
      </Stack>
    </Container>
  );
}

