import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: { atomicNumber: number; symbol: string; name: string; atomicWeight: number; category: string; row: number; col: number }[]; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const categories = useMemo(() => Array.from(new Set(props.elements.map(e => e.category))), [props.elements]);
  const categoryColors: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-primary-400, #38bdf8)',
    'alkaline earth metal': 'var(--ggui-color-success-400, #4ade80)',
    'transition metal': 'var(--ggui-color-warning-400, #fbbf24)',
    'post-transition metal': 'var(--ggui-color-info-400, #22d3ee)',
    'metalloid': 'var(--ggui-color-container, #ede9fe)',
    'reactive nonmetal': 'var(--ggui-color-primary-200, #bae6fd)',
    'noble gas': 'var(--ggui-color-error-300, #f87171)',
    'lanthanide': 'var(--ggui-color-primary-100, #e0f2fe)',
    'actinide': 'var(--ggui-color-primary-50, #f0f9ff)',
  };

  const filteredElements = useMemo(() => {
    const term = searchTerm.toLowerCase();
    return props.elements.filter(e => 
      e.name.toLowerCase().includes(term) || e.symbol.toLowerCase().includes(term)
    );
  }, [props.elements, searchTerm]);

  return { searchTerm, setSearchTerm, selectedElement, setSelectedElement, filteredElements, categoryColors, categories };
}

export default function Component(props: Props) {
  const { searchTerm, setSearchTerm, selectedElement, setSelectedElement, filteredElements, categoryColors, categories } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Heading level={1}>Periodic Table</Heading>
        <SearchField placeholder="Search by name or symbol..." value={searchTerm} onChange={setSearchTerm} />
        <Row gap={8} wrap>
          {categories.map(cat => (
            <Badge key={cat} style={{ backgroundColor: categoryColors[cat] }}>{cat}</Badge>
          ))}
        </Row>
        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1, 4px)' }}>
          {props.elements.map(el => (
            <button key={el.atomicNumber} aria-label={`${el.name}, Atomic Number ${el.atomicNumber}`} onClick={() => setSelectedElement(el)} style={{ 
              gridRow: el.row, gridColumn: el.col, padding: 'var(--ggui-spacing-1, 4px)',
              backgroundColor: categoryColors[el.category] || 'var(--ggui-color-surfaceVariant)',
              opacity: !searchTerm || filteredElements.includes(el) ? 1 : 0.2,
              cursor: 'pointer',
              borderRadius: 'var(--ggui-shape-radius-sm)',
              border: '1px solid var(--ggui-color-outlineVariant)',
              transition: 'all 0.2s ease',
            }}>
              <Text variant="caption" style={{ textAlign: 'left' }}>{el.atomicNumber}</Text>
              <Heading level={5} align="center">{el.symbol}</Heading>
            </button>
          ))}
        </Box>
        {selectedElement && (
          <Card shadow="md" padding={20}>
            <Heading level={3}>{selectedElement.name} ({selectedElement.symbol})</Heading>
            <Text>Atomic Number: {selectedElement.atomicNumber} | Weight: {selectedElement.atomicWeight}</Text>
            <Badge variant="primary">{selectedElement.category}</Badge>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

