import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id: string; name: string; price: number; currency: string; rating: number; reviewCount: number; stock: number; description: string; specifications: unknown[]; reviews: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);

  const handleQuantityChange = useCallback((delta: number) => {
    setQuantity(prev => Math.min(Math.max(1, prev + delta), props.product.stock));
  }, [props.product.stock]);

  const onAddToCart = useCallback(() => {
    handleAddToCart({ productId: props.product.id, quantity });
  }, [handleAddToCart, props.product.id, quantity]);

  return { quantity, handleQuantityChange, onAddToCart };
}

const StarRating = ({ rating }: { rating: number }) => (
  <Row gap={2} align="center">
    {[1, 2, 3, 4, 5].map((i) => (
      <Icon key={i} name={i <= Math.round(rating) ? 'check' : 'plus'} size={16} color={i <= Math.round(rating) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'} />
    ))}
    <Text variant="caption">({rating.toFixed(1)})</Text>
  </Row>
);

export default function Component(props: Props) {
  const { quantity, handleQuantityChange, onAddToCart } = useComponent(props);
  const { product } = props;

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Row align="start" gap={32}>
          <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="lg" padding={48} style={{ flex: 1, textAlign: 'center' }}>
            <Heading level={2}>{product.name}</Heading>
          </Box>
          <Stack gap={16} style={{ flex: 1 }}>
            <Heading level={1}>{product.name}</Heading>
            <StarRating rating={product.rating} />
            <Text variant="bodyLarge" color="var(--ggui-color-primary-600, #0284c7)">{product.currency} {product.price.toFixed(2)}</Text>
            <Badge variant={product.stock <= 0 ? 'error' : product.stock <= 5 ? 'warning' : 'success'}>
              {product.stock <= 0 ? 'Out of Stock' : product.stock <= 5 ? 'Low Stock' : 'In Stock'}
            </Badge>
            <Stack direction="horizontal" gap={8} align="center">
              <Button variant="secondary" size="sm" onClick={() => handleQuantityChange(-1)}>-</Button>
              <Text>{quantity}</Text>
              <Button variant="secondary" size="sm" onClick={() => handleQuantityChange(1)}>+</Button>
              <Button variant="primary" disabled={product.stock === 0} onClick={onAddToCart}>Add to Cart</Button>
            </Stack>
          </Stack>
        </Row>

        <Tabs variant="line" items={[
          { key: 'description', label: 'Description', content: <Text>{product.description}</Text> },
          { key: 'specs', label: 'Specifications', content: (
            <Table columns={[{key: 'key', header: 'Feature'}, {key: 'value', header: 'Details'}]} data={product.specifications as any[]} />
          )},
          { key: 'reviews', label: 'Reviews', content: (
            <Stack gap={16}>
              {product.reviews.map((r: any, i) => <Card key={i}><Text>{r.text}</Text></Card>)}
            </Stack>
          )}
        ]} />
      </Stack>
    </Container>
  );
}

