import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || props.avatarOptions[0],
    role: props.initialProfile?.role || props.roleOptions[0],
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme || 'light',
  });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStepValid = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    if (step === 2) return true;
    return true;
  }, [step, formData]);

  const nextStep = () => setStep(s => Math.min(s + 1, 3));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  return { step, formData, setFormData, isStepValid, nextStep, prevStep, handleComplete, validateEmail };
}

export default function Component(props: Props) {
  const { step, formData, setFormData, isStepValid, nextStep, prevStep, handleComplete, validateEmail } = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        <Heading level={2}>Setup your profile</Heading>
        <Progress value={(step - 1) * 50} max={100} showLabel />
        <Card padding={24} shadow="md">
          {step === 1 && (
            <Stack gap={16}>
              <Heading level={4}>1. Profile Details</Heading>
              <Input label="Name" value={formData.name} onChange={(name) => setFormData(d => ({ ...d, name }))} required error={!formData.name.trim() ? 'Name is required' : ''} />
              <Input label="Email" type="email" value={formData.email} onChange={(email) => setFormData(d => ({ ...d, email }))} required error={!validateEmail(formData.email) ? 'Invalid email format' : ''} />
              <Text variant="label">Avatar</Text>
              <Stack direction="horizontal" gap={8}>
                {props.avatarOptions.map(emoji => (
                  <Button key={emoji} size="sm" variant={formData.avatar === emoji ? 'primary' : 'outline'} onPress={() => setFormData(d => ({ ...d, avatar: emoji }))}>
                    {emoji}
                  </Button>
                ))}
              </Stack>
            </Stack>
          )}
          {step === 2 && (
            <Stack gap={16}>
              <Heading level={4}>2. Preferences</Heading>
              <Select label="Role" value={formData.role} options={props.roleOptions.map(r => ({ value: r, label: r }))} onChange={(role) => setFormData(d => ({ ...d, role }))} placeholder="Select a role" />
              <Checkbox label="Enable email notifications" checked={formData.emailNotifications} onChange={(emailNotifications) => setFormData(d => ({ ...d, emailNotifications }))} />
              <Toggle label={`Theme: ${formData.theme === 'dark' ? 'Dark' : 'Light'}`} checked={formData.theme === 'dark'} onChange={(checked) => setFormData(d => ({ ...d, theme: checked ? 'dark' : 'light' }))} />
            </Stack>
          )}
          {step === 3 && (
            <Stack gap={16}>
              <Heading level={4}>3. Review</Heading>
              <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius={8}>
                <Stack gap={8}>
                  <Text><strong>Name:</strong> {formData.name}</Text>
                  <Text><strong>Email:</strong> {formData.email}</Text>
                  <Text><strong>Role:</strong> {formData.role}</Text>
                  <Text><strong>Theme:</strong> {formData.theme}</Text>
                </Stack>
              </Box>
            </Stack>
          )}
        </Card>
        <Row justify="between">
          <Button variant="ghost" onPress={prevStep} disabled={step === 1}>Back</Button>
          {step < 3 ? (
            <Button onPress={nextStep} disabled={!isStepValid}>Next</Button>
          ) : (
            <Button variant="primary" onPress={() => handleComplete(formData)} disabled={!isStepValid}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
